class Solution:
    def distinctSequences(self, n):
        from math import gcd
        MOD = 10**9 + 7
        faces = range(1, 7)
        if n == 1:
            return 6
        dp = {}
        for a in faces:
            for b in faces:
                if a != b and gcd(a, b) == 1:
                    dp[(a, b)] = 1
        for _ in range(n - 2):
            nxt = {}
            for (a, b), cnt in dp.items():
                for c in faces:
                    if c != a and c != b and gcd(b, c) == 1:
                        nxt[(b, c)] = (nxt.get((b, c), 0) + cnt) % MOD
            dp = nxt
        return sum(dp.values()) % MOD

