class Solution:
    def distinctSequences(self, n):
        from math import gcd
        MOD = 10**9 + 7
        if n == 1:
            return 6
        valid = [[False] * 7 for _ in range(7)]
        for a in range(1, 7):
            for b in range(1, 7):
                if a != b and gcd(a, b) == 1:
                    valid[a][b] = True
        dp = [[0] * 7 for _ in range(7)]
        for a in range(1, 7):
            for b in range(1, 7):
                if valid[a][b]:
                    dp[a][b] = 1
        for _ in range(n - 2):
            nxt = [[0] * 7 for _ in range(7)]
            for a in range(1, 7):
                for b in range(1, 7):
                    if dp[a][b] == 0:
                        continue
                    for c in range(1, 7):
                        if c != a and valid[b][c]:
                            nxt[b][c] = (nxt[b][c] + dp[a][b]) % MOD
            dp = nxt
        total = 0
        for a in range(1, 7):
            for b in range(1, 7):
                total = (total + dp[a][b]) % MOD
        return total

