var distinctSequences = function(n) {
    const MOD = 1000000007n;
    const gcd = (x, y) => { while (y) { [x, y] = [y, x % y]; } return x; };
    if (n === 1) return 6;
    const valid = Array.from({length: 7}, () => new Array(7).fill(false));
    for (let a = 1; a < 7; a++) for (let b = 1; b < 7; b++) if (a !== b && gcd(a, b) === 1) valid[a][b] = true;
    let dp = Array.from({length: 7}, () => new Array(7).fill(0n));
    for (let a = 1; a < 7; a++) for (let b = 1; b < 7; b++) if (valid[a][b]) dp[a][b] = 1n;
    for (let step = 0; step < n - 2; step++) {
        const nxt = Array.from({length: 7}, () => new Array(7).fill(0n));
        for (let a = 1; a < 7; a++) for (let b = 1; b < 7; b++) {
            if (dp[a][b] === 0n) continue;
            for (let c = 1; c < 7; c++) {
                if (c !== a && valid[b][c]) nxt[b][c] = (nxt[b][c] + dp[a][b]) % MOD;
            }
        }
        dp = nxt;
    }
    let total = 0n;
    for (let a = 1; a < 7; a++) for (let b = 1; b < 7; b++) total = (total + dp[a][b]) % MOD;
    return Number(total);
};
